section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/secrets-management.json",
  "type": "object",
  "required": [
    "secret_name",
    "backend",
    "identity_method",
    "rotation_period_days",
    "policy_arn_or_path",
    "audit_log_destination",
    "injection_method"
  ],
  "properties": {
    "secret_name": {
      "type": "string",
      "description": "string (path-like, e.g. prod/api/db-password)"
    },
    "backend": {
      "type": "string",
      "description": "enum (vault | aws_secrets_manager | gcp_secret_manager | azure_keyvault)"
    },
    "identity_method": {
      "type": "string",
      "description": "enum (irsa | workload_identity | oidc | approle)"
    },
    "rotation_period_days": {
      "type": "integer",
      "description": "integer (\u226430)"
    },
    "policy_arn_or_path": {
      "type": "string",
      "description": "string (least-privilege policy reference)"
    },
    "audit_log_destination": {
      "type": "string",
      "description": "string (separate-account log destination)"
    },
    "injection_method": {
      "type": "string",
      "description": "enum (eso | csi | sdk_runtime_fetch)"
    }
  }
}
